import React from "react";
import "../App.css";

function Register({ onClose }) {
  return (
    <div className="modal-overlay">
      <div className="modal-box">
        <button className="modal-close" onClick={onClose}>×</button>
        <h2 className="modal-title">Register</h2>
        <input type="text" placeholder="Name" className="modal-input" />
        <input type="email" placeholder="Email" className="modal-input" />
        <input type="password" placeholder="Password" className="modal-input" />
        <button className="modal-btn">Register</button>
      </div>
    </div>
  );
}

export default Register;
